import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WeeklyForecast {
  day: string;
  high: number;
  low: number;
}

interface WeatherData {
  location: string;
  current: {
    temp: number;
    condition: string;
    humidity: number;
    windSpeed: number;
  };
  weeklyForecast: WeeklyForecast[];
  tempTrend: number[];
}

export default function Widget() {
  const weatherData = response.data as WeatherData;
  const { location, current, tempTrend, weeklyForecast } = weatherData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 400, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {location}
            </Typography>
            <Typography variant="h3" fontWeight={300} sx={{ my: 0.5 }}>
              {current.temp}°
            </Typography>
            <Typography variant="body1" color="text.secondary">
              {current.condition}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: tempTrend,
                  color: '#FFA726',
                  curve: 'natural',
                },
              ]}
              xAxis={[
                {
                  data: weeklyForecast.map((_, index) => index),
                  hide: true,
                },
              ]}
              yAxis={[{ hide: true }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>

          <Stack direction="row" spacing={3}>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Humidity
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {current.humidity}%
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Wind
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {current.windSpeed} mph
              </Typography>
            </Box>
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
